CREATE TABLE "ops_system_logs" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "level" character varying NOT NULL DEFAULT 'info',
  "source" character varying NOT NULL,
  "message" character varying NOT NULL,
  "request_id" character varying NOT NULL DEFAULT '',
  "trace_id" character varying NOT NULL DEFAULT '',
  "metadata_json" jsonb NULL,
  PRIMARY KEY ("id")
);

CREATE INDEX "opssystemlog_created_at" ON "ops_system_logs" ("created_at");
CREATE INDEX "opssystemlog_level_created_at" ON "ops_system_logs" ("level", "created_at");
CREATE INDEX "opssystemlog_source_created_at" ON "ops_system_logs" ("source", "created_at");
CREATE INDEX "opssystemlog_request_id" ON "ops_system_logs" ("request_id");
CREATE INDEX "opssystemlog_trace_id" ON "ops_system_logs" ("trace_id");
